import{_ as t,c as e,o,a1 as s}from"./chunks/framework.DILC4Csi.js";const u=JSON.parse('{"title":"トラブルシューティング: エラー解決 | opencode-mystatus","description":"opencode-mystatusのエラー解決方法を学びます。Token期限切れ、権限不足、APIリクエスト失敗など一般的な問題の解決策を提供します。","frontmatter":{"title":"トラブルシューティング: エラー解決 | opencode-mystatus","sidebarTitle":"トラブルシューティング","subtitle":"トラブルシューティング：クォータクエリ不可、Token期限切れ、権限問題","description":"opencode-mystatusのエラー解決方法を学びます。Token期限切れ、権限不足、APIリクエスト失敗など一般的な問題の解決策を提供します。","tags":["トラブルシューティング","一般的な質問","Token期限切れ","権限問題"],"prerequisite":["start-quick-start"],"order":1},"headers":[],"relativePath":"ja/vbgate/opencode-mystatus/faq/troubleshooting/index.md","filePath":"ja/vbgate/opencode-mystatus/faq/troubleshooting/index.md"}'),i={name:"ja/vbgate/opencode-mystatus/faq/troubleshooting/index.md"};function n(l,a,p,r,d,c){return o(),e("div",null,[...a[0]||(a[0]=[s(`<h1 id="トラブルシューティング-クォータクエリ不可、token期限切れ、権限問題" tabindex="-1">トラブルシューティング：クォータクエリ不可、Token期限切れ、権限問題 <a class="header-anchor" href="#トラブルシューティング-クォータクエリ不可、token期限切れ、権限問題" aria-label="Permalink to &quot;トラブルシューティング：クォータクエリ不可、Token期限切れ、権限問題&quot;">​</a></h1><p>opencode-mystatusプラグインを使用する際、様々なエラーに遭遇する可能性があります：認証ファイルの読み取り不可、OAuth Tokenの期限切れ、GitHub Copilotの権限不足、APIリクエスト失敗など。これらの一般的な問題は、通常、簡単な設定や再認証で解決できます。</p><h2 id="核心概念" tabindex="-1">核心概念 <a class="header-anchor" href="#核心概念" aria-label="Permalink to &quot;核心概念&quot;">​</a></h2><p>mystatusツールのエラー処理メカニズムは3層に分かれています：</p><ol><li><strong>認証ファイル読み取り層</strong>：<code>auth.json</code> の存在と形式を確認</li><li><strong>プラットフォームクエリ層</strong>：各プラットフォームが独立してクエリ、失敗しても他のプラットフォームに影響しない</li><li><strong>APIリクエスト層</strong>：ネットワークリクエストはタイムアウトやエラーを返す可能性があるが、ツールは他のプラットフォームを試行し続ける</li></ol><h2 id="問題トラブルシューティングリスト" tabindex="-1">問題トラブルシューティングリスト <a class="header-anchor" href="#問題トラブルシューティングリスト" aria-label="Permalink to &quot;問題トラブルシューティングリスト&quot;">​</a></h2><h3 id="問題1-認証ファイルを読み取れない" tabindex="-1">問題1：認証ファイルを読み取れない <a class="header-anchor" href="#問題1-認証ファイルを読み取れない" aria-label="Permalink to &quot;問題1：認証ファイルを読み取れない&quot;">​</a></h3><p><strong>エラーメッセージ</strong>：</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>❌ 認証ファイルを読み取れません: ~/.local/share/opencode/auth.json</span></span>
<span class="line"><span>エラー: ENOENT: no such file or directory</span></span></code></pre></div><p><strong>解決方法</strong>：</p><ol><li>OpenCodeがインストールされ、設定されていることを確認</li><li><code>~/.local/share/opencode/auth.json</code> が存在することを確認</li></ol><h3 id="問題2-設定済みのアカウントが見つかりません" tabindex="-1">問題2：設定済みのアカウントが見つかりません <a class="header-anchor" href="#問題2-設定済みのアカウントが見つかりません" aria-label="Permalink to &quot;問題2：設定済みのアカウントが見つかりません&quot;">​</a></h3><p><strong>エラーメッセージ</strong>：</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>設定済みのアカウントが見つかりません。</span></span></code></pre></div><p><strong>解決方法</strong>：</p><ol><li>OpenCodeで少なくとも1つのプラットフォーム（OpenAI、Zhipu AIなど）の認証を完了</li><li><code>auth.json</code> に正しい形式の設定が含まれていることを確認</li></ol><h3 id="問題3-openai-oauth-token期限切れ" tabindex="-1">問題3：OpenAI OAuth Token期限切れ <a class="header-anchor" href="#問題3-openai-oauth-token期限切れ" aria-label="Permalink to &quot;問題3：OpenAI OAuth Token期限切れ&quot;">​</a></h3><p><strong>エラーメッセージ</strong>：</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>⚠️ OAuth認証が期限切れ、OpenCodeでOpenAIモデルを一度使用して認証をリフレッシュしてください。</span></span></code></pre></div><p><strong>解決方法</strong>：</p><ol><li>OpenCodeでOpenAIモデルを一度使用する</li><li>Tokenが自動的にリフレッシュされる</li></ol><h3 id="問題4-apiリクエスト失敗-一般" tabindex="-1">問題4：APIリクエスト失敗（一般） <a class="header-anchor" href="#問題4-apiリクエスト失敗-一般" aria-label="Permalink to &quot;問題4：APIリクエスト失敗（一般）&quot;">​</a></h3><p><strong>エラーメッセージ</strong>：</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>OpenAI APIリクエスト失敗 (401): Unauthorized</span></span></code></pre></div><p><strong>解決方法</strong>：</p><ol><li>TokenまたはAPIキーが有効であることを確認</li><li>ネットワーク接続を確認</li><li>再認証を試みる</li></ol><h3 id="問題5-リクエストタイムアウト" tabindex="-1">問題5：リクエストタイムアウト <a class="header-anchor" href="#問題5-リクエストタイムアウト" aria-label="Permalink to &quot;問題5：リクエストタイムアウト&quot;">​</a></h3><p><strong>エラーメッセージ</strong>：</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>リクエストタイムアウト (10秒）</span></span></code></pre></div><p><strong>解決方法</strong>：</p><ol><li>ネットワーク接続を確認</li><li>再試行する</li></ol><h3 id="問題6-github-copilotクォータクエリが使用不可" tabindex="-1">問題6：GitHub Copilotクォータクエリが使用不可 <a class="header-anchor" href="#問題6-github-copilotクォータクエリが使用不可" aria-label="Permalink to &quot;問題6：GitHub Copilotクォータクエリが使用不可&quot;">​</a></h3><p><strong>エラーメッセージ</strong>：</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>⚠️ GitHub Copilot クォータクエリが一時的に利用できません。</span></span></code></pre></div><p><strong>解決方法</strong>：Fine-grained PATを作成して設定（<a href="./../../advanced/copilot-auth/">Copilot認証設定</a>を参照）</p><h3 id="問題7-google-cloudにproject-idがない" tabindex="-1">問題7：Google Cloudにproject_idがない <a class="header-anchor" href="#問題7-google-cloudにproject-idがない" aria-label="Permalink to &quot;問題7：Google Cloudにproject_idがない&quot;">​</a></h3><p><strong>エラーメッセージ</strong>：</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>⚠️ project_idがないため、クォータをクエリできません。</span></span></code></pre></div><p><strong>解決方法</strong>：<code>antigravity-accounts.json</code> に <code>projectId</code> または <code>managedProjectId</code> を追加</p><h3 id="問題8-zhipu-ai-z-ai-apiが無効データを返す" tabindex="-1">問題8：Zhipu AI / Z.ai APIが無効データを返す <a class="header-anchor" href="#問題8-zhipu-ai-z-ai-apiが無効データを返す" aria-label="Permalink to &quot;問題8：Zhipu AI / Z.ai APIが無効データを返す&quot;">​</a></h3><p><strong>エラーメッセージ</strong>：</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>Zhipu APIリクエスト失敗 (200): {&quot;code&quot;: 401, &quot;msg&quot;: &quot;Invalid API key&quot;}</span></span></code></pre></div><p><strong>解決方法</strong>：</p><ol><li>APIキーが正しいことを確認</li><li>APIキーの権限を確認</li></ol><h2 id="まとめ" tabindex="-1">まとめ <a class="header-anchor" href="#まとめ" aria-label="Permalink to &quot;まとめ&quot;">​</a></h2><p>mystatusのエラー処理は3層に分かれています：認証ファイル読み取り、プラットフォームクエリ、APIリクエスト。エラーに遭遇したら、まずエラーメッセージのキーワードを確認し、対応する解決策を見つけます。最も一般的な問題には以下が含まれます：</p><ol><li><strong>認証ファイルの問題</strong>：<code>auth.json</code> の存在と形式を確認</li><li><strong>Token期限切れ</strong>：OpenCodeで対応モデルを一度使用してTokenをリフレッシュ</li><li><strong>APIエラー</strong>：HTTPステータスコードに基づいて権限問題かサーバー側の問題かを判断</li><li><strong>Copilot特殊権限</strong>：新しいOAuth統合ではFine-grained PATを設定する必要がある</li><li><strong>Google設定</strong>：クォータをクエリするにはproject_idが必要</li></ol><p>大部分のエラーは設定や再認証で解決できます。</p><h2 id="次のレッスン" tabindex="-1">次のレッスン <a class="header-anchor" href="#次のレッスン" aria-label="Permalink to &quot;次のレッスン&quot;">​</a></h2><blockquote><p>次のレッスンでは <strong><a href="/docs/opencodedocs/ja/vbgate/opencode-mystatus/faq/security/">セキュリティとプライバシー：ローカルファイルアクセス、APIマスキング、公式インターフェース</a></strong> を学びます。</p></blockquote><hr><h2 id="付録-ソースコード参照" tabindex="-1">付録：ソースコード参照 <a class="header-anchor" href="#付録-ソースコード参照" aria-label="Permalink to &quot;付録：ソースコード参照&quot;">​</a></h2><details><summary><strong>クリックしてソースコードの場所を展開</strong></summary><table tabindex="0"><thead><tr><th>機能</th><th>ファイルパス</th><th>行番号</th></tr></thead><tbody><tr><td>エラー処理メインロジック</td><td><a href="https://github.com/vbgate/opencode-mystatus/blob/main/plugin/mystatus.ts" target="_blank" rel="noreferrer"><code>plugin/mystatus.ts</code></a></td><td>41-87</td></tr></tbody></table></details>`,53)])])}const g=t(i,[["render",n]]);export{u as __pageData,g as default};
